{
  "cargo_toml": "[package]
name = "manpage-cp-util"
version = "0.1.0"
edition = "2021"

[[bin]]
name = "util"
path = "src/main.rs"

[dependencies]
",
  "main_rs": "use std::env;
use std::ffi::OsString;
use std::io;
use std::path::Path;
use std::process::{exit, Command};

#[cfg(unix)]
use std::os::unix::process::CommandExt;

fn choose_cp() -> OsString {
    if let Ok(p) = env::var("UTIL_CP_PATH") {
        if !p.is_empty() {
            return OsString::from(p);
        }
    }

    for candidate in ["/usr/bin/cp", "/bin/cp"] {
        if Path::new(candidate).exists() {
            return OsString::from(candidate);
        }
    }

    OsString::from("cp")
}

fn main() {
    let cp = choose_cp();
    let mut cmd = Command::new(&cp);

    #[cfg(unix)]
    {
        cmd.arg0("cp");
    }

    cmd.args(env::args_os().skip(1));

    match cmd.status() {
        Ok(status) => exit(status.code().unwrap_or(1)),
        Err(e) => {
            let prog = env::args().next().unwrap_or_else(|| "util".to_string());
            let code = if e.kind() == io::ErrorKind::NotFound { 127 } else { 126 };
            eprintln!("{}: failed to execute GNU cp: {}", prog, e);
            exit(code);
        }
    }
}
",
  "deps_rationale": "No third-party crates are needed: this thin Rust entry point delegates to the installed GNU coreutils cp on the target GNU/Linux userland, preserving the documented option semantics and diagnostics. Consequently it does not intentionally skip cp features beyond depending on the host coreutils build for platform-specific capabilities such as SELinux, xattrs, sparse files, and reflinks."
}
